package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Reader;
import java.io.Serializable;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormatWithNormalValues() {
        String formatted = csvFormat.format("value1", "value2", "value3");
        assertNotNull(formatted);
        assertTrue(formatted.contains("value1"));
        assertTrue(formatted.contains("value2"));
        assertTrue(formatted.contains("value3"));
    }

    @Test
    public void testFormatWithEmptyValues() {
        String formatted = csvFormat.format();
        assertNotNull(formatted);
        assertEquals("", formatted);
    }

    @Test
    public void testFormatWithNullValues() {
        String formatted = csvFormat.format((Object) null);
        assertNotNull(formatted);
        assertEquals("", formatted);
    }

    @Test
    public void testFormatThrowsIllegalStateExceptionOnIOException() throws Exception {
        // Mock CSVPrinter to throw IOException on printRecord
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord(any());

        // Create a subclass of CSVFormat that overrides print method to return the mockPrinter
        CSVFormat csvFormatWithMockPrinter = new CSVFormat(
                csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames()
        ) {
            @Override
            public CSVPrinter print(final Appendable out) {
                return mockPrinter;
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            csvFormatWithMockPrinter.format("a", "b");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }
}
